  purple: { from: "#8b5cf6", to: "#6366f1" },
  blue:   { from: "#06b6d4", to: "#6366f1" },
  green:  { from: "#10b981", to: "#06b6d4" },
  orange: { from: "#f97316", to: "#eab308" },
  pink:   { from: "#ec4899", to: "#ef4444" },
};

