import * as React from "react";
import { cn } from "@/lib/utils";
import { ArrowUpRight } from "lucide-react";

interface ArticleCardProps {
  title: string;
  excerpt?: string;
  date?: string;
  tags?: string[];
  coverImage?: string;
  href?: string;
  variant?: "default" | "horizontal" | "minimal";
